#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int *h = (int*)malloc(n * sizeof(int));
        int *m = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &h[i], &m[i]);
        }
        int Q = 0;
        printf("%d\n", Q);
        for (int i = 0; i < n - 1; i++) {
            if ((h[i] < h[i + 1] && m[i] > m[i + 1]) || (h[i] > h[i + 1] && m[i] < m[i + 1])) {
                Q++;
                printf("%d %d\n", 0, 0);
            }
        }
        free(h);
        free(m);
    }
    return 0;
}

