code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] h = new int[n];
            int[] m = new int[n];
            for (int i = 0; i < n; i++) {
                h[i] = sc.nextInt();
                m[i] = sc.nextInt();
            }
            int Q = 0;
            System.out.println(Q);
            for (int i = 0; i < n - 1; i++) {
                if ((h[i] < h[i + 1] && m[i] > m[i + 1]) || (h[i] > h[i + 1] && m[i] < m[i + 1])) {
                    Q++;
                    System.out.println(0 + " " + 0);
                }
            }
        }
    }
}

